// solve returns the count of non-empty subsets s such that the induced subgraph on s is connected
// and the sum of values in s is even.
func solve(nums []int64, edges [][]int64) int64 {
	n := len(nums)
	count := int64(0)

	// Adjacency matrix representation of the graph
	adj := make([][]bool, n)
	for i := 0; i < n; i++ {
		adj[i] = make([]bool, n)
	}
	for _, edge := range edges {
		u := int(edge[0])
		v := int(edge[1])
		adj[u][v] = true
		adj[v][u] = true
	}

	// Iterate over all non-empty subsets of nodes. There are 2^n - 1 such subsets.
	// A subset can be represented by a bitmask from 1 to 2^n - 1.
	for mask := 1; mask < (1 << n); mask++ {
		// 1. Calculate the sum of values for the current subset s
		sum := int64(0)
		subsetNodes := []int{}
		for i := 0; i < n; i++ {
			if (mask>>i)&1 == 1 {
				sum += nums[i]
				subsetNodes = append(subsetNodes, i)
			}
		}

		// Check condition 2: Sum must be even
		if sum%2 != 0 {
			continue
		}

		// 2. Check condition 1: The induced subgraph must be connected
		if len(subsetNodes) == 0 {
			// Should not happen as mask starts from 1
			continue
		}

		// Use BFS or DFS to check connectivity within the induced subgraph

		// Start BFS from the first node in the subset
		startNode := subsetNodes[0]
		visited := make(map[int]bool)
		queue := []int{startNode}
		visited[startNode] = true
		visitedCount := 1

		for len(queue) > 0 {
			u := queue[0]
			queue = queue[1:]

			// Check neighbors of u that are also in the subset s
			for v := 0; v < n; v++ {
				// v must be in the subset (check mask) AND not yet visited
				if ((mask>>v)&1 == 1) && !visited[v] && adj[u][v] {
					visited[v] = true
					visitedCount++
					queue = append(queue, v)
				}
			}
		}

		// If the number of visited nodes equals the size of the subset, the induced subgraph is connected.
		if visitedCount == len(subsetNodes) {
			count++
		}
	}

	return count
}
