	// Find the first node in the set s (the smallest index with the bit set)
	startNode := -1
	for i := 0; i < n; i++ {
		if (mask>>i)&1 == 1 {
			startNode = i
			break
		}
	}

	// If the mask is 0 (empty set), this function shouldn't be called based on problem constraints,
	// but we handle it defensively.
	if startNode == -1 {
		return false // Should not happen for non-empty subset s
	}

	// Use BFS or DFS to check connectivity within the induced subgraph
	queue := []int{startNode}
	visited := 1 << startNode
	count := 1

	for len(queue) > 0 {
		u := queue[0]
		queue = queue[1:]

